import { useState, useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X, ChevronDown, User, LogOut, Settings } from "lucide-react";

const navLinks = [
	{ name: "Home", href: "#home" },
	{ name: "Destinations", href: "#destinations" },
	{ name: "Why Us", href: "#features" },
	{ name: "How It Works", href: "#how-it-works" },
	{ name: "Testimonials", href: "#testimonials" },
];

export const Header = ({ user, onLogoutClick }) => {
	const [scrolled, setScrolled] = useState(false);
	const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
	const [dropdownOpen, setDropdownOpen] = useState(false);
	const dropdownRef = useRef(null);

	useEffect(() => {
		const handleScroll = () => setScrolled(window.scrollY > 60);
		window.addEventListener("scroll", handleScroll);
		return () => window.removeEventListener("scroll", handleScroll);
	}, []);

	useEffect(() => {
		const handleClickOutside = (e) => {
			if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
				setDropdownOpen(false);
			}
		};
		document.addEventListener("mousedown", handleClickOutside);
		return () => document.removeEventListener("mousedown", handleClickOutside);
	}, []);

	const scrollToSection = (href) => {
		const el = document.querySelector(href);
		if (el) el.scrollIntoView({ behavior: "smooth" });
		setMobileMenuOpen(false);
	};

	return (
		<motion.header
			initial={{ y: -100 }}
			animate={{ y: 0 }}
			transition={{ duration: 0.6, ease: "easeOut" }}
			className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
				scrolled
					? "bg-navy/95 shadow-xl shadow-navy/25 backdrop-blur-md"
					: "bg-gradient-to-b from-navy/70 via-navy/40 to-transparent"
			}`}
		>
			<div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
				<div className="flex items-center justify-between h-[72px]">
					{/* Logo */}
					<Link to="/" className="flex items-center gap-3 group shrink-0">
						<div className="h-11 w-11 sm:h-12 sm:w-12 rounded-full bg-white/5 p-1 ring-1 ring-white/15 group-hover:ring-gold/50 transition">
							<img
								src="/.png"
								alt="OffTrail Nepal"
								className="h-full w-full rounded-full object-contain"
							/>
						</div>
						<div className="flex flex-col leading-none">
							<span className="text-lg sm:text-xl font-extrabold text-white tracking-tight font-heading">
								OffTrail
								<span className="text-gold ml-1">Nepal</span>
							</span>
							<span className="text-[10px] sm:text-[11px] text-white/50 tracking-[0.28em] uppercase">
								Himalayan Treks
							</span>
						</div>
					</Link>

					{/* Desktop Nav */}
					<nav className="hidden lg:flex items-center gap-1">
						{navLinks.map((link) => (
							<button
								key={link.name}
								onClick={() => scrollToSection(link.href)}
								className="relative px-4 py-2 text-[13px] font-semibold uppercase tracking-wider text-white/70 hover:text-gold transition-colors duration-300 group"
							>
								{link.name}
								<span className="absolute bottom-0 left-1/2 -translate-x-1/2 w-0 h-0.5 bg-gold rounded-full group-hover:w-3/4 transition-all duration-300" />
							</button>
						))}
					</nav>

					{/* Right Side */}
					<div className="flex items-center gap-3">
						{user ? (
							<div className="relative" ref={dropdownRef}>
								<button
									onClick={() => setDropdownOpen(!dropdownOpen)}
									className="flex items-center gap-2.5 px-3 py-2 rounded-xl hover:bg-white/10 transition group"
								>
									<div className="h-9 w-9 rounded-full bg-gradient-to-br from-gold to-gold-light flex items-center justify-center text-navy font-bold text-sm ring-2 ring-gold/30">
										{user.full_name?.charAt(0).toUpperCase() || "U"}
									</div>
									<div className="hidden md:block text-left">
										<p className="text-sm font-semibold text-white leading-tight">
											{user.full_name || "User"}
										</p>
										<p className="text-[11px] text-white/50 capitalize">
											{user.user_type}
										</p>
									</div>
									<ChevronDown
										className={`h-4 w-4 text-white/50 transition-transform duration-300 ${
											dropdownOpen ? "rotate-180" : ""
										}`}
									/>
								</button>

								<AnimatePresence>
									{dropdownOpen && (
										<motion.div
											initial={{ opacity: 0, y: -8, scale: 0.96 }}
											animate={{ opacity: 1, y: 0, scale: 1 }}
											exit={{ opacity: 0, y: -8, scale: 0.96 }}
											transition={{ duration: 0.2, ease: "easeOut" }}
											className="absolute right-0 mt-3 w-64 bg-white rounded-2xl shadow-2xl border border-gray-100 py-2 overflow-hidden"
										>
											<div className="px-4 py-3 border-b border-gray-100">
												<p className="text-sm font-bold text-navy">
													{user.full_name}
												</p>
												<p className="text-xs text-gray-500 mt-0.5">
													{user.email}
												</p>
												<span className="inline-block mt-2 px-3 py-1 bg-gold/10 text-gold-dark text-xs font-semibold rounded-full capitalize">
													{user.user_type}
												</span>
											</div>
											<div className="py-1">
												<button className="w-full text-left px-4 py-2.5 text-sm text-gray-700 hover:bg-gold-50 flex items-center gap-3 transition">
													<User className="h-4 w-4 text-gray-400" />
													My Profile
												</button>
												<button className="w-full text-left px-4 py-2.5 text-sm text-gray-700 hover:bg-gold-50 flex items-center gap-3 transition">
													<Settings className="h-4 w-4 text-gray-400" />
													Settings
												</button>
											</div>
											<div className="border-t border-gray-100 pt-1">
												<button
													onClick={() => {
														onLogoutClick(true);
														setDropdownOpen(false);
													}}
													className="w-full text-left px-4 py-2.5 text-sm text-red-600 hover:bg-red-50 flex items-center gap-3 transition"
												>
													<LogOut className="h-4 w-4" />
													Logout
												</button>
											</div>
										</motion.div>
									)}
								</AnimatePresence>
							</div>
						) : (
							<div className="hidden sm:flex items-center gap-3">
								<Link
									to="/login"
									className="px-5 py-2.5 text-sm font-semibold text-white border border-white/20 hover:border-gold/40 hover:text-gold rounded-lg transition-all duration-300"
								>
									Log in
								</Link>
								<Link
									to="/register"
									className="px-5 py-2.5 text-sm font-bold text-navy rounded-lg transition-all duration-300 shadow-lg shadow-gold/20 hover:shadow-gold/40 hover:scale-[1.02]"
									style={{
										background:
											"linear-gradient(135deg, #C8932A 0%, #E0B04A 100%)",
									}}
								>
									Sign Up Free
								</Link>
							</div>
						)}

						{/* Mobile Menu Toggle */}
						<button
							onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
							className="lg:hidden p-2 rounded-lg text-white hover:bg-white/10 transition"
							aria-label="Toggle menu"
						>
							{mobileMenuOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
						</button>
					</div>
				</div>
			</div>

			{/* Mobile Menu */}
			<AnimatePresence>
				{mobileMenuOpen && (
					<motion.div
						initial={{ opacity: 0, height: 0 }}
						animate={{ opacity: 1, height: "auto" }}
						exit={{ opacity: 0, height: 0 }}
						transition={{ duration: 0.3, ease: "easeInOut" }}
						className="lg:hidden bg-navy-dark/98 backdrop-blur-xl border-t border-white/10 overflow-hidden"
					>
						<div className="px-4 py-5 space-y-1 max-w-md mx-auto">
							{navLinks.map((link, i) => (
								<motion.button
									key={link.name}
									initial={{ opacity: 0, x: -20 }}
									animate={{ opacity: 1, x: 0 }}
									transition={{ delay: i * 0.05 }}
									onClick={() => scrollToSection(link.href)}
									className="block w-full text-left px-4 py-3.5 text-white/80 hover:text-gold hover:bg-white/5 rounded-xl transition font-medium text-[15px]"
								>
									{link.name}
								</motion.button>
							))}
							{!user && (
								<div className="pt-5 mt-3 border-t border-white/10 space-y-3">
									<Link
										to="/login"
										onClick={() => setMobileMenuOpen(false)}
										className="block w-full text-center px-4 py-3.5 text-white border border-white/20 rounded-xl hover:border-gold/40 hover:text-gold transition font-semibold"
									>
										Log in
									</Link>
									<Link
										to="/register"
										onClick={() => setMobileMenuOpen(false)}
										className="block w-full text-center px-4 py-3.5 text-navy rounded-xl font-bold shadow-lg shadow-gold/20"
										style={{
											background:
												"linear-gradient(135deg, #C8932A 0%, #E0B04A 100%)",
										}}
									>
										Sign Up Free
									</Link>
								</div>
							)}
						</div>
					</motion.div>
				)}
			</AnimatePresence>
		</motion.header>
	);
};
